package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  @Test
  void newFactory_createReturnsAdapterForExactType() {
    // Arrange
    Class<String> type = String.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<String> typeAdapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(type, typeAdapter);
    Gson gson = mock(Gson.class);
    TypeToken<String> matchingTypeToken = TypeToken.get(String.class);

    // Act
    @SuppressWarnings("unchecked")
    TypeAdapter<String> createdAdapter = factory.create(gson, matchingTypeToken);

    // Assert
    assertSame(typeAdapter, createdAdapter);
  }

  @Test
  void newFactory_createReturnsNullForDifferentType() {
    // Arrange
    Class<String> type = String.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<String> typeAdapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(type, typeAdapter);
    Gson gson = mock(Gson.class);
    TypeToken<Integer> differentTypeToken = TypeToken.get(Integer.class);

    // Act
    TypeAdapter<?> createdAdapter = factory.create(gson, differentTypeToken);

    // Assert
    assertNull(createdAdapter);
  }

  @Test
  void newFactory_toStringContainsTypeAndAdapter() {
    // Arrange
    Class<String> type = String.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<String> typeAdapter = mock(TypeAdapter.class);
    when(typeAdapter.toString()).thenReturn("MyTypeAdapter");
    TypeAdapterFactory factory = TypeAdapters.newFactory(type, typeAdapter);

    // Act
    String factoryString = factory.toString();

    // Assert
    assertTrue(factoryString.contains(type.getName()));
    assertTrue(factoryString.contains("MyTypeAdapter"));
  }
}
